	('42744122-37b3-418c-8ce6-0827156c65e8', 'd79b3ee1-e129-4f56-9dbc-2a848825f3a4', NULL, 'Pain on the medial side of her L knee', false, false, true, 'M62.81, M25.562, M25.462', NULL, NULL, NULL, NULL, NULL, NULL, '{Pain}', 'Pt is 3 days s/p L TKA. Current pain 5/10, improves to 4/10 with rest/meds, worsens to 6/10 with activity. Mobility limited to 40 ft ambulation with FWW; needs moderate assist x1 for bed mobility, transfers, and stairs.', true, '2026-04-09 16:44:12.745+00', false, NULL, NULL, '2026-04-09 16:44:12.465579+00', '2026-04-09 16:44:12.465579+00', NULL, false, NULL, false, false, false, false, false, false, false, NULL, NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
