	('bbfe4bc4-5717-420f-a7ea-f584e0c284b6', 'c3d4e5f6-3333-4000-c000-000000000003', 1, 'Chronic venous leg ulcer left lower limb', false, false, false, 'I87.312', NULL, 'left_lower_leg', 'stage_3', 4.00, 3.20, 0.30, '{pain,edema,drainage}', 'Chronic VLU present for 4 months. Failed 8 weeks of compression therapy. ABI 0.92 bilateral. Wound bed shows granulation tissue with fibrinous slough at margins. Skin substitute application recommended.', false, NULL, true, '2026-04-07 09:15:00+00', 'def47068-35f4-45fa-94bf-361460cb9c12', '2026-04-09 17:13:34.652924+00', '2026-04-09 17:13:34.652924+00', NULL, false, NULL, false, false, false, false, false, false, false, NULL, NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
	('c9c32ff4-954e-417c-afc4-9ee0dd4b6196', 'c3d4e5f6-4444-4000-c000-000000000004', 1, 'Pressure ulcer stage 3 sacral area', false, false, false, 'L89.153', NULL, 'sacral', 'stage_3', 6.00, 4.50, 2.00, '{pain,necrotic_tissue,drainage}', 'Stage 3 sacral pressure ulcer with undermining at 3-6 o clock position. Sharp debridement performed. Wound bed now viable with granulation tissue. Requires matrix application and advanced wound care protocol.', false, NULL, true, '2026-04-08 14:00:00+00', 'def47068-35f4-45fa-94bf-361460cb9c12', '2026-04-09 17:13:34.652924+00', '2026-04-09 17:13:34.652924+00', NULL, false, NULL, false, false, false, false, false, false, false, NULL, NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
