	('abbc2c78-2e76-4706-8c1e-dcdec5d8c837', 'bdee19b1-408c-4fee-aa58-cd5343997182', NULL, 'Pain on the medial side of her L knee', false, false, true, 'M62.81, M25.562, M25.462', NULL, NULL, NULL, NULL, NULL, NULL, '{Pain}', 'Pt. is 75 y/o Caucasian female, 3 days s/p L TKA. Currently reports pain of 5/10, worsening to 6/10 with activity. PT goals include increasing stair mobility, bed mobility, independent transfers, and long distance ambulation.', true, '2026-04-09 23:49:15.599+00', false, NULL, NULL, '2026-04-09 23:49:19.395967+00', '2026-04-09 23:49:19.395967+00', NULL, false, NULL, false, false, false, false, false, false, false, NULL, NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
	('9bc3613e-a564-4cf5-9213-145dd1aeb34c', '46401b18-92cc-4356-924c-ccdb1ee16dc9', NULL, 'Pain on the medial side of her L knee', false, false, true, 'M62.81, M25.562, M25.462', NULL, NULL, NULL, NULL, NULL, NULL, '{Pain}', 'Pt. is 75 y/o Caucasian female, 3 days s/p L TKA. Current pain level is 5/10 (at rest 4/10, with activity 6/10). Pt. requires moderate assist x1 for bed mobility, transfers, and stairs. Ambulation limited to 40 ft due to pain.', true, '2026-04-10 11:29:43.029+00', false, NULL, NULL, '2026-04-10 11:29:43.103275+00', '2026-04-10 11:29:43.103275+00', NULL, false, NULL, false, false, false, false, false, false, false, NULL, NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
	('f01239cc-0dae-4d81-afd5-727005014997', '7e200eb2-d00f-4ad0-9a70-b93889bc998d', NULL, 'Pain on the medial side of her L knee for 2 years', false, false, true, 'M62.81, M25.562, M25.462', NULL, NULL, NULL, NULL, NULL, NULL, '{Pain}', '75 y/o female, 3 days post-op L TKA. Experiencing pain with walking, weight-bearing, and using LLE. Current pain is 5/10, resting pain is 4/10, worst pain is 6/10. Patient requires moderate assist x1 for bed mobility, transfers, and stairs.', true, '2026-04-10 11:34:41.226+00', false, NULL, NULL, '2026-04-10 11:34:41.27965+00', '2026-04-10 11:34:41.27965+00', NULL, false, NULL, false, false, false, false, false, false, false, NULL, NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
	('1a93ce71-6a02-422b-9097-669b5cf8365c', '44e7b95d-de38-420c-90cf-3470285da511', 5, 'Pain on the medial side of her L knee', false, false, true, 'M62.81, M25.562, M25.462', NULL, NULL, NULL, NULL, NULL, NULL, '{Pain}', '75 y/o female 3 days post-op L TKA. Current pain 5/10, improves with rest and hydrocodone. AROM -3 to 65 degrees flexion. Difficulty with bed mobility, transfers, and stairs.', true, '2026-04-12 16:29:35.091+00', false, NULL, NULL, '2026-04-12 16:29:25.427514+00', '2026-04-12 16:29:25.427514+00', NULL, false, NULL, true, false, false, false, false, false, false, 'LT', NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, 'Inpatient rehabilitation to increase stair mobility, bed mobility, independent transfers, long distance ambulation, and to increase overall pt. safety.', NULL, NULL, 'John Smith', '2026-04-12', NULL, NULL, '2026-04-14 15:01:13.133+00', 'def47068-35f4-45fa-94bf-361460cb9c12'),
	('9fbd2943-85f7-412b-bc4f-514a4bf5dca1', '77fd8a3f-77a5-40ca-b9c3-b7829aad14ec', NULL, 'Pain on the medial side of her L knee for 2 years', false, false, true, 'M62.81, M25.562, M25.462', NULL, NULL, NULL, NULL, NULL, NULL, '{Pain}', 'Pt is 75 y/o female, 3 days s/p L TKA. Currently experiencing pain 5/10. Needs moderate assist x1 with bed mobility, transfers, and stairs.', true, '2026-04-12 16:24:54.743+00', false, NULL, NULL, '2026-04-12 16:24:54.171279+00', '2026-04-12 16:24:54.171279+00', NULL, false, NULL, true, false, false, false, false, false, false, 'LT', NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, 'Inpatient rehabilitation to increase stair mobility, bed mobility, independent transfers, long distance ambulation, and to increase overall pt safety.', NULL, NULL, 'John Smith', '2026-04-12', NULL, NULL, '2026-04-14 15:08:28.223+00', NULL),
	('c4862e98-c308-4e0a-85ee-15bc4d2e7ebc', 'e4338c2b-2d73-4f02-824e-84fabfe278d9', NULL, 'Pain in left knee', false, true, false, 'M62.81, M25.562, M25.462', NULL, 'Left knee', NULL, NULL, NULL, NULL, '{Pain}', '75 year old Caucasian female 3 days post L Total Knee Arthroplasty. Patient admitted to inpatient rehabilitation for stair mobility, bed mobility, independent transfers, long distance ambulation, and safety. History of OA with tricompartmental arthritis. Current pain 5/10 at best, 4/10 at rest, decreased with hydrocodone PRN. Pain increased with walking, weight-bearing, and LLE use. Pain worst 6/10. Pain is dull, achy, primarily over anterior L knee. Ambulates approximately 40 ft before needing therapeutic rest.', true, '2026-04-14 16:08:19.01+00', false, NULL, NULL, '2026-04-14 16:08:14.99638+00', '2026-04-14 16:08:14.99638+00', NULL, false, NULL, true, false, false, false, false, false, false, 'LT', NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, 'Inpatient rehabilitation secondary to required assistance, home set-up, and limited family support. Bilateral UE support for static/dynamic balance and moderate assist x1. Moderate assist x1 with stairs using 2 railings x3 steps.', NULL, NULL, NULL, '2026-04-14', 'Dr. Lisa Chen', NULL, NULL, NULL),
	('2ad58b6a-f030-4ff7-9b64-08984990c842', '0b711e8c-6ffb-462b-88b2-90d4ece96f10', NULL, 'Pain in left knee', false, true, false, 'M62.81, M25.562, M25.462', NULL, 'Left knee', NULL, NULL, NULL, NULL, '{Pain}', 'Patient is 75-year-old Caucasian female who received left total knee arthroplasty (LTKA) 3 days ago. Referred to inpatient rehabilitation to increase stair mobility, bed mobility, independent transfers, long distance ambulation, and overall safety. Pain on medial side of left knee for 2 years, worsened 6 months ago causing cessation of exercise and volunteering. Main complaint is pain with descending stairs and pain/swelling in left knee 3 months ago. Current pain 5/10, decreases with rest and hydrocodone. Pain increased with walking, weight-bearing, and LLE use; worst pain 6/10. Pain is dull, achy, primarily located over anterior left knee. Patient up walking 2 times daily with significant pain in left knee. Moderate assist needed for bed mobility, transfers, and ambulating on stairs.', true, '2026-04-14 16:11:14.132+00', false, NULL, NULL, '2026-04-14 16:11:07.083958+00', '2026-04-14 16:11:07.083958+00', NULL, false, NULL, true, false, false, false, false, false, false, 'LT', NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, 'Inpatient rehabilitation secondary to required assistance, home set-up, and limited family support', NULL, NULL, NULL, '2026-04-14', 'Dr. Lisa Chen', NULL, NULL, NULL),
	('2c097478-d312-4d5a-9959-ceda7b10ad13', '2304e2fc-e965-4354-bb0b-b21647d9fa8b', NULL, 'Pain in left knee following total knee arthroplasty', false, true, false, 'M62.81, M25.562, M25.462', NULL, 'Left knee', NULL, NULL, NULL, NULL, '{Pain}', '75-year-old Caucasian female 3 days post-LTKA. History of OA with tricompartmental arthritis and medial femoral condyle approximation. Pain on medial side of left knee for 2 years 6 months, worsened 6 months ago forcing cessation of exercise and volunteering. Main complaint: pain with descending stairs and swelling in left knee 3 months ago. LTKA performed 4/14/18 with successful placement of three prosthetic components. Current pain 5/10 at best, 4/10 decreased with rest and hydrocodone PRN. Pain increased with walking, weight-bearing, and LLE use; worst is 6/10. Pain dull, achy, primarily over anterior left knee. Patient up walking 2 times daily with significant pain. Able to ambulate approximately 40 feet before requiring therapeutic rest.', true, '2026-04-14 16:27:30.609+00', false, NULL, NULL, '2026-04-14 16:27:26.272893+00', '2026-04-14 16:27:26.272893+00', NULL, false, NULL, true, false, false, false, false, false, false, 'LT', NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, 'Inpatient rehabilitation secondary to required assistance, home set-up, and limited family support. PT referred for evaluation and treatment to increase stair mobility, bed mobility, independent transfers, long distance ambulation, and overall safety.', NULL, NULL, NULL, '2026-04-14', 'Dr. Lisa Chen', NULL, NULL, NULL),
	('d40cb89e-b681-45d6-bd54-0a7584853127', '44bc4bea-46b6-4371-869c-55743b7cdaba', NULL, 'Pain in left knee following total knee arthroplasty', false, true, false, 'M62.81, M25.562, M25.462', NULL, 'Left knee', NULL, NULL, NULL, NULL, '{Pain}', '75 year old Caucasian female 3 days post left total knee arthroplasty. History of osteoarthritis with medial femoral condyle and tibial plateau involvement. Imaging showed loss of joint space with lateral shift of patella. Current pain 5/10 at best, 4/10 at rest and decreased with hydrocodone. Pain increased with walking, weight-bearing, and LLE use. Pain worst 6/10. Pain is dull, achy, primarily located over anterior left knee. Patient ambulates approximately 40 feet before needing therapeutic rest.', true, '2026-04-14 16:29:14.152+00', false, NULL, NULL, '2026-04-14 16:29:09.547073+00', '2026-04-14 16:29:09.547073+00', NULL, false, NULL, true, false, false, false, false, false, false, 'LT', NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, 'Inpatient rehabilitation for increased stair mobility, bed mobility, independent transfers, long distance ambulation, and overall safety. Bilateral UE support for static/dynamic balance and moderate assist x1. Moderate assist x1 with stairs using 2 railings x3 steps.', NULL, NULL, NULL, '2026-04-14', 'Dr. Lisa Chen', NULL, NULL, NULL),
	('bea976fe-b802-4778-a896-994aa0fafae7', '59c247b7-31fb-4e10-bfa5-c3cd2cad31ad', NULL, 'Pain in left knee', false, false, false, 'M62.81, M25.562, M25.462', NULL, 'Left knee', NULL, NULL, NULL, NULL, '{Pain}', '75-year-old Caucasian female 3 days post L Total Knee Arthroplasty (TKA). History of medial femoral condyle and tibial plateau tricompartmental arthritis with loss of joint space and lateral shift of patella. Pain primarily located over anterior L knee. Current pain 5/10 at best, 4/10 at rest, 6/10 at worst. Pain increased with walking, weight-bearing, and LLE use. Pain dull, achy primarily over anterior L knee. Decreased with rest and hydrocodone PRN. Patient ambulatory with moderate assist xl for bed mobility, transfers, and stairs. Patient unsafe on stairs. Bilateral UE support required for static/dynamic balance and moderate assist x1.', true, '2026-04-14 16:31:02.431+00', false, NULL, NULL, '2026-04-14 16:30:50.491131+00', '2026-04-14 16:30:50.491131+00', NULL, false, NULL, true, false, false, false, false, false, false, 'LT', NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, 'Inpatient rehabilitation secondary to required assistance, home set-up, and limited family support. FWW x 40 ft with pain. Moderate assist x1 with 2 railings x3 steps, patient unsafe. Bilateral UE support for static/dynamic balance and moderate assist x1.', NULL, NULL, NULL, '2026-04-14', 'Dr. Lisa Chen', NULL, NULL, NULL),
	('7595c7df-c8c9-4970-ba0a-13762e5fc3e5', 'bfde550f-0595-4f36-aef3-b054a6e2ad4b', NULL, 'Pain in left knee following total knee arthroplasty', false, true, false, 'M62.81, M25.562, M25.462', NULL, 'Left knee', NULL, NULL, NULL, NULL, '{Pain}', '75-year-old Caucasian female status post left total knee arthroplasty 3 days ago. Patient admitted to inpatient rehabilitation. History of osteoarthritis with 2 years 6 months of left knee pain. Pain became severe 6 months ago causing cessation of exercise and volunteering. TKA performed 4/14/18 with successful placement of three prosthetic components. Current pain 5/10 at best, 4/10 baseline, decreased with rest and hydrocodone. Pain increased with walking, weight-bearing, and LLE use; worst pain 6/10. Pain is dull, achy, primarily located over anterior left knee. AROM: -3° L knee extension, 65° L knee flexion. PROM: -5° L knee extension, 70° L knee flexion. Ambulation: FWW x 40 ft with pain. Stairs: moderate assist x1 with 2 railings x3 steps, patient unsafe. Balance: bilateral UE support for static/dynamic balance, moderate assist x1. DC Recommendation: inpatient rehabilitation secondary to required assistance, home set-up, limited family support.', true, '2026-04-14 16:31:51.116+00', false, NULL, NULL, '2026-04-14 16:31:45.637388+00', '2026-04-14 16:31:45.637388+00', NULL, false, NULL, true, false, false, false, false, false, false, 'LT', NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, 'Inpatient rehabilitation to increase stair mobility, bed mobility, independent transfers, long distance ambulation, and overall safety', NULL, NULL, 'John Smith', '2026-04-14', NULL, NULL, '2026-04-14 16:33:02.007+00', NULL),
	('c01e7759-9d9d-4160-aef1-e1d1974f5843', '265d5264-cde6-4d8c-a732-4f72a3ec69af', NULL, 'Pain in left knee', false, true, false, 'M62.81, M25.562, M25.462', NULL, 'Left knee', NULL, NULL, NULL, NULL, '{Pain}', '75-year-old Caucasian female 3 days post left total knee arthroplasty (TKA). Patient in acute care hospital for 3 days then transferred to inpatient rehabilitation. History of osteoarthritis with left knee pain for 2 years 6 months, worsening 6 months ago. Pain with descending stairs and swelling 3 months ago. TKA performed on 4/14/18 with successful placement of three prosthetic components and no complications. Current pain 5/10 at best, 4/10, decreased with rest and hydrocodone PRN. Pain increased with walking, weight-bearing, and LLE use; worst pain 6/10. Pain dull, achy, primarily located over anterior left knee. Range of motion limited: AROM -3° left knee extension, 65° left knee flexion; PROM -5° left knee extension, 70° left knee flexion. Ambulation FWW x 40 feet with pain. Stairs require moderate assist x1 with 2 railings x3 steps, patient unsafe. Balance bilateral UE support needed for static/dynamic balance with moderate assist x1. Able to ambulate approximately 40 feet before needing rest secondary to pain.', true, '2026-04-14 16:38:14.61+00', false, NULL, NULL, '2026-04-14 16:38:06.127503+00', '2026-04-14 16:38:06.127503+00', NULL, false, NULL, true, false, false, false, false, false, false, 'LT', NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, 'Inpatient rehabilitation secondary to required assistance, home set-up, and limited family support. Focus on increasing stair mobility, bed mobility, independent transfers, long distance ambulation, and overall safety.', NULL, NULL, NULL, '2026-04-14', 'Dr. Lisa Chen', NULL, NULL, NULL),
	('8f9846e9-5108-4d5e-9064-48f85b64f3a6', '7dd66910-d36c-42b6-8327-ccfdac61222e', NULL, 'Pain in left knee following total knee arthroplasty', false, true, false, 'M62.81', NULL, 'Left knee', NULL, NULL, NULL, NULL, '{Pain}', '75-year-old Caucasian female 3 days post-L TKA for osteoarthritis. History of medial femoral condyle and tibial plateau compartmental arthritis with loss of joint space and lateral patellar shift. Current pain 5/10 at best, 4/10 at rest, 6/10 at worst. Pain dull, achy, primarily over anterior L knee. Pain increased with walking, weight-bearing, and LLE use. Patient ambulatory approximately 40 feet before needing therapeutic rest. Up walking 2 times daily with significant pain. Requires moderate assist for bed mobility, transfers, and stair climbing.', true, '2026-04-14 16:43:17.409+00', false, NULL, NULL, '2026-04-14 16:43:12.396006+00', '2026-04-14 16:43:12.396006+00', NULL, false, NULL, true, false, false, false, false, false, false, 'LT', NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, 'Inpatient rehabilitation secondary to required assistance, home set-up, and limited family support. Treatment for evaluation and management of post-TKA pain and functional mobility restoration.', NULL, NULL, NULL, '2026-04-14', 'Dr. Lisa Chen', NULL, NULL, NULL),
