	('2e18ceb8-cb52-459e-8a9c-c4134c167e4c', '8f447f1d-f478-4160-a19a-3a018f822020', NULL, 'Pain in left knee', false, true, false, 'M62.81, M25.562, M25.462', NULL, 'Left knee', NULL, NULL, NULL, NULL, '{Pain}', '75 year old Caucasian female 3 days post left total knee arthroplasty. Patient admitted to inpatient rehabilitation to increase stair mobility, bed mobility, independent transfers, long distance ambulation, and overall safety. History of pain on medial side of left knee for 2 years 6 months, worsened 3 months ago. Pain with descending stairs and swelling in left knee. TKA performed 4/14/18 with successful placement of component hardware with three prosthetic components. No complications with surgery. Current pain 5/10 at best, 4/10, decreased with rest and hydrocodone PRN. Pain increased with walking, weight-bearing, and use of left lower extremity. Pain worst is 6/10. Pain is dull, achy, located over anterior left knee.', true, '2026-04-14 18:09:19.221+00', false, NULL, NULL, '2026-04-14 18:09:15.426356+00', '2026-04-14 18:09:15.426356+00', NULL, false, NULL, true, false, false, false, false, false, false, 'LT', NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, 'Inpatient rehabilitation secondary to required assistance, home set-up, and limited family support. Bilateral UE support for static/dynamic balance and moderate assist x1. Pt able to ambulate approximately 40 ft before needing therapeutic rest.', NULL, NULL, NULL, '2026-04-14', 'Dr. Lisa Chen', NULL, NULL, NULL),
	('92f25981-9a25-4328-948a-24ae74e06f12', '3aa53d38-f315-487a-9591-1a3782da9621', NULL, 'Bilateral knee pain', false, false, false, 'M25.561', NULL, NULL, NULL, NULL, NULL, NULL, '{Pain}', '72-year-old male presenting for preoperative evaluation for right knee arthroplasty. Patient has end-stage osteoarthritis of bilateral knees with bone-on-bone medial compartment involvement and varus alignment. Failed nonoperative management including multiple Orthovisc injections, PRP injections, and oral analgesics. Patient is diabetic with history of elevated hemoglobin A1c requiring medical optimization prior to surgery.', true, '2026-04-14 18:14:49.723+00', false, NULL, NULL, '2026-04-14 18:14:46.532222+00', '2026-04-14 18:14:46.532222+00', NULL, false, NULL, true, true, false, false, false, false, false, 'RT', NULL, NULL, NULL, NULL, NULL, false, false, false, 'normal', NULL, 'Right total knee arthroplasty. Patient will complete medical clearance. Patient is a candidate for aspirin for postoperative DVT prophylaxis. Follow-up postoperative care. Physical therapy required postoperatively to prevent arthrofibrosis.', NULL, NULL, NULL, '2026-04-14', 'Dr. Lisa Chen', NULL, NULL, NULL),
	('b3fc6411-c378-459f-a855-a43a9fda3beb', 'e6f9fffa-9908-4225-b993-a7295fe1b46f', NULL, NULL, false, false, false, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{}', NULL, false, NULL, false, NULL, NULL, '2026-04-17 14:46:39.09507+00', '2026-04-17 14:46:39.09507+00', NULL, false, NULL, false, false, false, false, false, false, false, NULL, NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, NULL, NULL, NULL, 'John Does', '2026-04-17', NULL, NULL, NULL, NULL),
	('0b2e5fb2-e34c-48b4-b26d-f975a71e5132', '38cb4fe3-18d3-4dc1-a405-257cd2993524', NULL, 'Left knee pain', false, false, false, 'M17.12', NULL, NULL, NULL, NULL, NULL, NULL, '{Pain}', '71-year-old female with primary osteoarthritis of left knee with end-stage findings on imaging. Failed nonoperative management including cortisone injections and Mobic therapy. Patient elected to proceed with left total knee arthroplasty. Medical clearance required. Candidate for aspirin postoperative DVT prophylaxis.', true, '2026-04-14 18:22:22.607+00', false, NULL, NULL, '2026-04-14 18:22:14.625677+00', '2026-04-14 18:22:14.625677+00', NULL, false, NULL, true, false, false, false, false, false, false, 'LT', NULL, NULL, NULL, NULL, NULL, false, false, false, 'normal', NULL, 'Left total knee arthroplasty recommended. Patient requires medical clearance prior to surgery. Postoperative anticoagulation for DVT prophylaxis. Outpatient physical therapy required after surgery.', NULL, NULL, NULL, '2026-04-14', 'Dr. Lisa Chen', NULL, NULL, NULL),
	('d2fb06a0-7ee8-4cbb-b3d2-4da57b69fe45', 'dad52984-051a-497b-8600-f0075b53efd8', NULL, 'Left knee pain', false, false, false, 'M25.562', NULL, NULL, NULL, NULL, NULL, NULL, '{Pain}', '64-year-old female presenting for orthopedic evaluation of left knee pain with constant pain since November 2025. Pain with walking and bending. Uses a cane. Failed nonoperative management including cortisone injection and PRP injection on 11/20/2025. MRI shows marked knee joint osteoarthritis of medial and lateral compartments with subchondral edema, medial meniscus extrusion, and complete ACL tear. X-ray shows medial joint space narrowing to 2 mm and patellofemoral osteoarthritic changes. Patient has elected to proceed with left total knee arthroplasty. Requires medical clearance and will continue tobacco cessation.', true, '2026-04-14 18:27:19.444+00', false, NULL, NULL, '2026-04-14 18:27:16.703097+00', '2026-04-14 18:27:16.703097+00', NULL, false, NULL, true, false, false, false, false, false, false, 'LT', NULL, NULL, NULL, NULL, NULL, false, false, false, 'normal', NULL, 'Patient recommended for left total knee arthroplasty. Requires medical clearance. Needs outpatient physical therapy after surgery. Post-operative anticoagulation required to decrease risk of blood clots. Follow-up preoperative and postoperative care. Continue tobacco cessation.', NULL, NULL, NULL, '2026-04-14', 'Dr. Lisa Chen', NULL, NULL, NULL),
	('d539524e-f9b3-4249-9834-ce89d07ef17b', '8107edf8-7135-421c-acb6-a28f9cc993a0', NULL, 'Pain in left knee following total knee arthroplasty', false, true, false, 'M62.81, M25.562, M25.462', NULL, 'Left knee', NULL, NULL, NULL, NULL, '{Pain}', '75-year-old Caucasian female 3 days post-LTKA. History of OA with pain on medial side of L knee for 2 years 6 months. Pain became severe 6 months ago. Main complaint is pain with descending stairs and pain/swelling in L knee 3 months ago. TKA performed on 4/14/18 with successful placement of three prosthetic components. Current pain 5/10 at best, 4/10 decreased with rest and hydrocodone, increased with walking, weight-bearing, and LLE use. Pain at worst 6/10. Pain is dull, achy, primarily located directly over anterior L knee. Patient able to ambulate approximately 40 ft before needing therapeutic rest secondary to pain.', true, '2026-04-14 19:19:50.747+00', false, NULL, NULL, '2026-04-14 19:19:48.37831+00', '2026-04-14 19:19:48.37831+00', NULL, true, 'Hydrocodone PRN', true, false, false, false, false, false, false, 'LT', NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, 'Inpatient rehabilitation secondary to required assistance, home set-up, and limited family support. Bilateral UE support for static/dynamic balance and moderate assist x1. Treatment for evaluation and treatment to increase stair mobility, bed mobility, independent transfers, long distance ambulation, and overall patient safety. Moderate assist x1 with stairs using 2 railings for 3 steps. Patient unsafe on stairs.', NULL, NULL, NULL, '2026-04-14', 'Dr. Lisa Chen', NULL, NULL, NULL),
	('1a7372c0-aa8c-413c-8fe4-9f325485f7a6', '98714507-26aa-4a0c-9eac-94e8a2625304', NULL, 'Pain in left knee', false, true, false, 'M62.81', NULL, 'Left knee', NULL, NULL, NULL, NULL, '{Pain}', 'Patient is a 75-year-old Caucasian female who received a L TKA 3 days ago. Patient spent 3 days in a local acute care hospital. Patient sent to inpatient rehabilitation to increase stair mobility, bed mobility, independent transfers, long distance ambulation, and to increase overall patient safety. Patient complains of pain on the medial side of her left knee for 2 years; 6 months ago the pain became too severe and the patient had to stop exercise and volunteering. Patient''s main complaint was pain with descending stairs and pain/swelling in left knee 3 months ago. Patient consulted with physician and proceeded with a left total knee arthroplasty following evaluation of radiographic imaging. Current pain is 5/10, pain at best is 4/10 and is decreased with rest and hydrocodone. Pain is increased with walking, weight-bearing, and when using LLE a lot; pain at worst is a 6/10. Pain is dull, achy, and primarily located directly over the anterior left knee.', true, '2026-04-15 07:14:43.713+00', false, NULL, NULL, '2026-04-15 07:14:43.807048+00', '2026-04-15 07:14:43.807048+00', NULL, false, NULL, true, false, false, false, false, false, false, 'LT', NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, 'Inpatient rehabilitation secondary to required assistance, home set-up, and limited family support', NULL, NULL, NULL, '2026-04-15', 'Dr. Lisa Chen', NULL, NULL, NULL),
	('2c302c56-d0e0-4ee9-97dd-6b3187f8ffc5', 'a8cffc36-35da-4aea-a73c-d8ee1de57e0e', NULL, 'Pain in left knee', false, true, false, 'M62.81', NULL, 'Left knee', NULL, NULL, NULL, NULL, '{Pain}', 'Patient is a 75 y/o Caucasian female who received a L TKA 3 days ago. Patient spent 3 days in a local acute care hospital. Patient sent to inpatient rehabilitation to increase stair mobility, bed mobility, independent transfers, long distance ambulation, and to increase overall pt safety. Patient c/o pain on the medial side of her L knee for 2 years. 6 months ago the pain became too severe and the pt had to stop exercise and volunteering. Patient is 3 days s/p LTKA and is feeling better with a current pain of 5/10. Pain at best is 4/10 and is decreased with rest and hydrocodone PRN. Pain is increased with walking, weight-bearing, and when using LLE a lot, pain at worst is a 6/10. Pain is dull, achy, and primarily located directly over the anterior L knee. Patient has been up walking 2 times a day. Patient walks down the hallway and back with a lot of pain in her L knee. Patient states she needs moderate assist x1 with bed mobility, transfers, and ambulating on stairs. Patient only able to ambulate approximately 40 ft before needing therapeutic rest secondary to pain.', true, '2026-04-15 08:18:39.198+00', false, NULL, NULL, '2026-04-15 08:18:39.230729+00', '2026-04-15 08:18:39.230729+00', NULL, false, NULL, true, false, false, false, false, false, false, 'LT', NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, 'Inpatient rehabilitation secondary to required assistance, home set-up, and limited family support', NULL, NULL, NULL, '2026-04-15', 'Dr. Lisa Chen', NULL, NULL, NULL),
	('f28de4b3-d43b-4f91-8808-ea34bbd25466', 'b8d29e43-33ad-4626-b1b4-08dba7731838', NULL, 'Pain in left knee', false, true, false, 'M62.81', NULL, 'Left knee', NULL, NULL, NULL, NULL, '{Pain}', 'Patient is a 75 y/o Caucasian female who received a L TKA 3 days ago. Patient spent 3 days in a local acute care hospital. Patient sent to inpatient rehabilitation to increase stair mobility, bed mobility, independent transfers, long distance ambulation, and to increase overall pt safety. Patient c/o pain on the medial side of her L knee for 2 years. 6 months ago the pain became too severe and the pt had to stop exercise and volunteering. Pts main complaint was pain with descending stairs and pain/swelling in L knee. 3 months ago pt consulted with her physician and proceeded with a L TKA following evaluation of radiographic imaging. TKA was performed on 4/14/18 with successful placement of component hardware with three prosthetic components. No complications with surgery. Pt is 3 days s/p L TKA and is feeling better with a current pain of 5/10. Pain at best is 4/10 and is decreased with rest and hydrocodone PRN. Pain is increased with walking, weight-bearing, and when using LLE a lot, pain at worst is a 6/10. Pain is dull, achy, and primarily located directly over the anterior L knee. Patient has been up walking 2 times a day. Patient walks down the hallway and back with a lot of pain in her L knee. Patient states she needs moderate assist x1 with bed mobility, transfers, and ambulating on stairs. Patient only able to ambulate approximately 40 ft before needing therapeutic rest secondary to pain.', true, '2026-04-15 08:39:45.87+00', false, NULL, NULL, '2026-04-15 08:39:45.895287+00', '2026-04-15 08:39:45.895287+00', NULL, false, NULL, true, false, false, false, false, false, false, 'LT', NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, 'Inpatient rehabilitation secondary to required assistance, home set-up, and limited family support', NULL, NULL, NULL, '2026-04-