	('cfc4c7ea-1a23-4d5b-b176-44c0ef58dc46', 'dba8c5aa-3bdf-48d0-9b4b-17b89ced9957', NULL, 'Left knee pain and swelling', false, false, false, 'M62.81', NULL, 'Left knee', NULL, NULL, NULL, NULL, '{Pain}', '75 year old Caucasian female who received L TKA 3 days ago. Pt spent 3 days in a local acute care hospital. Pt sent to inpatient rehabilitation to increase stair mobility, bed mobility, independent transfers, long distance ambulation, and to increase overall pt safety. Pt c/o pain on the medial side of her L knee for 2 years. 6 months ago the pain became too severe and the pt had to stop exercise and volunteering. Pts main complaint was pain with descending stairs and pain/swelling in L knee. 3 months ago pt consulted with her physician and proceeded with a L TKA following evaluation of radiographic imaging. TKA was performed on 4/14/18 with successful placement of component hardware with three prosthetic components. No complications with surgery. Pt is 3 days s/p L TKA and is feeling better with a current pain of 5/10. Pain at best is 4/10 and is decreased with rest and hydrocodone PRN. Pain is increased with walking, weight-bearing, and when using LLE a lot, pain at worst is a 6/10. Pain is dull, achy, and primarily located directly over the anterior L knee.', true, '2026-04-15 11:29:53.991+00', false, NULL, NULL, '2026-04-15 11:29:53.810557+00', '2026-04-15 11:29:53.810557+00', NULL, false, NULL, true, false, false, false, false, false, false, 'LT', NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, 'Inpatient rehabilitation secondary to required assistance, home set-up, and limited family support', NULL, NULL, NULL, '2026-04-15', 'Dr. Lisa Chen', NULL, NULL, NULL),
	('0f3608e7-b801-4048-ad97-6010a135d33e', '669ac73a-822f-4ff1-bb18-0fc54972d15e', NULL, 'Left knee pain and effusion post-total knee arthroplasty', false, true, false, 'M62.81', NULL, 'Left knee', NULL, NULL, NULL, NULL, '{Pain}', 'Patient is a 75-year-old Caucasian female who received a L TKA 3 days ago. History of osteoarthritis with medial femoral condyle and tibial plateau involvement. Patient has pain in left knee, pain with descending stairs, pain/swelling in left knee. Current pain 5/10 at best, 4/10 decreased with rest and hydrocodone, increased with walking, weight-bearing, and using left lower extremity. Pain is dull, achy, primarily located directly over anterior left knee.', true, '2026-04-15 13:01:26.143+00', false, NULL, NULL, '2026-04-15 13:01:26.236943+00', '2026-04-15 13:01:26.236943+00', NULL, false, NULL, true, false, false, false, false, false, false, 'LT', NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, 'Inpatient rehabilitation secondary to required assistance, home set-up, and limited family support. Bilateral upper extremity support for static/dynamic balance and moderate assist x1. Patient able to ambulate approximately 40 feet before needing therapeutic rest secondary to pain.', NULL, NULL, NULL, '2026-04-15', 'Dr. Lisa Chen', NULL, NULL, NULL),
	('4c23684a-c762-4826-9409-a83ee19e692b', '0aa37013-3114-46ef-9f51-391bb59d1edd', NULL, 'Bilateral knee pain', false, false, false, 'M25.562', NULL, NULL, NULL, NULL, NULL, NULL, '{Pain}', '59-year-old female presenting for orthopedic evaluation with bilateral knee pain for many years. Pain worse in right knee with walking and bending. Affects quality of life. Previously had physical therapy. Has avoided injections and is not taking pain medication. MRI previously obtained. Patient has deferred on additional physical therapy, injections, or pain medication. Patient has elected to proceed with right total knee arthroplasty.', true, '2026-04-16 13:38:15.58+00', false, NULL, NULL, '2026-04-16 13:38:15.664072+00', '2026-04-16 13:38:15.664072+00', NULL, false, NULL, true, false, false, false, false, false, false, 'bilateral', NULL, NULL, NULL, NULL, NULL, false, false, false, 'normal', NULL, 'Right total knee arthroplasty recommended. Patient needs medical clearance. Aspirin candidate for postoperative DVT prophylaxis. Outpatient physical therapy required after surgery. Follow-up preoperative and postoperative care.', NULL, NULL, NULL, '2026-04-16', 'Dr. Lisa Chen', NULL, NULL, NULL),
	('5317baa1-8012-4b68-b710-795ccd83552a', 'd856aba0-7ae6-4d80-b516-06bbc0d1299d', NULL, 'Left knee pain and swelling', false, true, false, 'M62.81', NULL, 'Left knee', NULL, NULL, NULL, NULL, '{Pain}', 'Patient is a 75-year-old Caucasian female who received a L TKA 3 days ago. Patient spent 3 days in a local acute care hospital. Patient sent to inpatient rehabilitation to increase stair mobility, bed mobility, independent transfers, long distance ambulation, and to increase overall patient safety. Patient c/o pain on the medial side of her L knee for 2 years 6 months ago the pain became too severe and the pt had to stop exercise and volunteering. Patient''s main complaint was pain with descending stairs and pain/swelling in L knee 3 months ago pt consulted with her physician and proceeded with a L TKA following evaluation of radiographic imaging. TKA was performed on 4/14/18 with successful placement of component hardware with three prosthetic components. No complications with surgery. Patient is 3 days s/p L TKA and is feeling better with a current pain of 5/10. Pain at best is 4/10 and is decreased with rest and hydrocodone PRN. Pain is increased with walking, weight-bearing, and when using LLE a lot; pain at worst is a 6/10. Pain is dull, achy, and primarily located directly over the anterior L knee.', true, '2026-04-16 14:43:30.366+00', false, NULL, NULL, '2026-04-16 14:43:30.482004+00', '2026-04-16 14:43:30.482004+00', NULL, false, NULL, true, false, false, false, false, false, false, 'LT', NULL, NULL, NULL, NULL, NULL, false, false, false, NULL, NULL, 'Inpatient rehabilitation secondary to required assistance, home set-up, and limited family support', NULL, NULL, NULL, '2026-04-16', 'Dr. Lisa Chen', NULL, NULL, NULL),
